SELECT upload_notes
FROM uploads
WHERE upload_id = 1;

SELECT browser_name
FROM browsers
WHERE version = (SELECT MAX(version) FROM browsers);

SELECT DISTINCT L.language_name
FROM languages AS L
INNER JOIN benchmark_results AS BR ON L.language_id = BR.language_id;

SELECT cpu_usage, memory_usage, execution_time
FROM benchmark_results
WHERE result_id = 0;
